'use client'

import { useState } from 'react'
import { useGetInvoices, InvoiceStatusBadge, AmountDisplay } from '@/entities/invoice'
import { INVOICE_STATUS_VALUES } from '@/entities/invoice'
import { DataTable } from '@/shared/ui/data-table/data-table'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import type { ColumnDef } from '@tanstack/react-table'
import type { Invoice, InvoiceStatus } from '@/entities/invoice'
import { formatCurrency } from '@/shared/lib/formatCurrency'
import { formatDate } from '@/shared/lib/formatDate'

export default function InvoiceListPage() {
  const [status, setStatus] = useState<InvoiceStatus | ''>('')
  const [page, setPage] = useState(0)
  const { data, isLoading } = useGetInvoices({ status: status || undefined, page, size: 20 })

  const invoices = data?.data ?? []

  const columns: ColumnDef<Invoice>[] = [
    { accessorKey: 'invoiceNumber', header: 'Invoice #' },
    { accessorKey: 'patientId', header: 'Patient' },
    {
      accessorKey: 'totalAmount',
      header: 'Amount',
      cell: ({ row }) => formatCurrency(row.original.totalAmount),
    },
    {
      accessorKey: 'status',
      header: 'Status',
      cell: ({ row }) => <InvoiceStatusBadge status={row.original.status} />,
    },
    {
      accessorKey: 'createdAt',
      header: 'Created',
      cell: ({ row }) => formatDate(row.original.createdAt),
    },
  ]

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">Billing</h1>
      <Select value={status} onValueChange={(v) => setStatus(v as InvoiceStatus | '')}>
        <SelectTrigger className="w-40">
          <SelectValue placeholder="All Statuses" />
        </SelectTrigger>
        <SelectContent>
          <SelectItem value="">All Statuses</SelectItem>
          {INVOICE_STATUS_VALUES.map((s) => (
            <SelectItem key={s} value={s}>{s}</SelectItem>
          ))}
        </SelectContent>
      </Select>
      {isLoading ? (
        <div className="py-8 text-center text-muted-foreground">Loading...</div>
      ) : (
        <DataTable
          columns={columns}
          data={invoices}
          pagination={{ page, pageSize: 20, totalPages: data?.totalPages ?? 1, onPageChange: setPage }}
        />
      )}
    </div>
  )
}

'use client'

import { useState } from 'react'
import { useAuthStore } from '@/features/auth'
import { useGetInvoices, InvoiceCard, InvoiceStatusBadge } from '@/entities/invoice'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { INVOICE_STATUS_VALUES } from '@/entities/invoice'
import type { InvoiceStatus } from '@/shared/types/enums'

export default function PatientInvoicesPage() {
  const user = useAuthStore((s) => s.user)
  const [status, setStatus] = useState<InvoiceStatus | ''>('')

  const { data, isLoading } = useGetInvoices({
    patientId: user?.patientId ?? '',
    status: status || undefined,
    size: 20,
  })

  const invoices = data?.data ?? []

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">My Invoices</h1>
      <Select value={status} onValueChange={(v) => setStatus(v as InvoiceStatus | '')}>
        <SelectTrigger className="w-40">
          <SelectValue placeholder="All Statuses" />
        </SelectTrigger>
        <SelectContent>
          <SelectItem value="">All Statuses</SelectItem>
          {INVOICE_STATUS_VALUES.map((s) => (
            <SelectItem key={s} value={s}>{s}</SelectItem>
          ))}
        </SelectContent>
      </Select>
      {isLoading ? (
        <div className="py-8 text-center text-muted-foreground">Loading...</div>
      ) : invoices.length === 0 ? (
        <div className="py-8 text-center text-muted-foreground">No invoices found.</div>
      ) : (
        <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
          {invoices.map((inv) => (
            <InvoiceCard key={inv.id} invoice={inv} />
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useGetVisit, useSignVisit, useIssuePrescription, useScheduleFollowUp, VisitDetail, PrescriptionCard, VisitStatusBadge, PdfDownloadButton } from '@/entities/visit'
import { useGetAppointment } from '@/entities/appointment'
import { LoadingSpinner } from '@/shared/ui/loading-spinner/loading-spinner'
import { useParams } from 'next/navigation'

export default function VisitPage() {
  const params = useParams()
  const appointmentId = params.appointmentId as string

  const { data: appointment, isLoading: aptLoading } = useGetAppointment(appointmentId)
  const visitId = appointment?.id ?? ''

  const { data: visit, isLoading: visitLoading } = useGetVisit(visitId)

  if (aptLoading || visitLoading) return <LoadingSpinner />

  if (!visit) {
    return (
      <div className="space-y-6">
        <h1 className="text-2xl font-bold">Visit</h1>
        <p className="text-muted-foreground">No visit record found for this appointment.</p>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">Visit Details</h1>
        <PdfDownloadButton visitId={visit.id} />
      </div>
      <VisitDetail visit={visit} />
      {visit.prescriptions.length > 0 && (
        <div className="space-y-3">
          <h2 className="text-lg font-semibold">Prescriptions</h2>
          <div className="grid gap-3 sm:grid-cols-2">
            {visit.prescriptions.map((rx) => (
              <PrescriptionCard key={rx.id} prescription={rx} />
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

"use client";

import { Refine } from "@refinedev/core";
import { useAuthStore } from "@/features/auth/model/authStore";
import { ROLE_ALLOWED_PATHS } from "@/shared/config/appConfig";

const authProvider = {
  login: async ({ email, password }: { email: string; password: string }) => {
    await useAuthStore.getState().login(email, password);
    return { success: true } as const;
  },
  logout: async () => {
    useAuthStore.getState().logout();
    return { success: true, redirectTo: "/login" } as const;
  },
  check: async () => {
    const { isAuthenticated } = useAuthStore.getState();
    if (isAuthenticated) return { authenticated: true } as const;
    return { authenticated: false, redirectTo: "/login", logout: true } as const;
  },
  onError: async (error: { status?: number }) => {
    if (error?.status === 401) {
      useAuthStore.getState().logout();
      return { redirectTo: "/login", logout: true } as const;
    }
    return {} as const;
  },
  getPermissions: async () => {
    const { user } = useAuthStore.getState();
    return user?.role || null;
  },
  getIdentity: async () => {
    const { user } = useAuthStore.getState();
    return user;
  },
};

const accessControlProvider = {
  can: async ({
    resource,
    action,
  }: {
    resource?: string;
    action: string;
  }) => {
    const { user } = useAuthStore.getState();
    if (!user) return { can: false } as const;
    if (user.role === "Admin") return { can: true } as const;

    const allowedPaths = ROLE_ALLOWED_PATHS[user.role] || [];
    const resourcePathMap: Record<string, string[]> = {
      patients: ["/patient", "/reception/patients", "/admin/patients"],
      doctors: ["/doctor", "/admin/doctors"],
      appointments: [
        "/patient/appointments",
        "/reception/appointments",
        "/admin/appointments",
      ],
      visits: ["/doctor/visits", "/doctor/queue"],
      invoices: [
        "/patient/invoices",
        "/reception/billing",
        "/admin/billing",
      ],
      users: ["/admin/users"],
      reports: ["/admin/reports"],
      "audit-log": ["/admin/audit-log"],
    };
    const resourcePaths = resourcePathMap[resource || ""] || [];
    const canAccess = resourcePaths.some((p) =>
      allowedPaths.some((ap) => ap.startsWith(p) || p.startsWith(ap))
    );
    return { can: canAccess } as const;
  },
};

const resources = [
  { name: "patients", list: "/admin/patients", show: "/patient/profile" },
  { name: "doctors", list: "/admin/doctors", show: "/doctor/profile" },
  { name: "appointments", list: "/admin/appointments" },
  { name: "visits", list: "/doctor/queue" },
  { name: "invoices", list: "/admin/billing" },
  { name: "users", list: "/admin/users" },
  { name: "reports", list: "/admin/reports" },
  { name: "audit-log", list: "/admin/audit-log" },
];

export function RefineProvider({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <Refine
      authProvider={authProvider}
      accessControlProvider={accessControlProvider}
      resources={resources}
      options={{
        syncWithLocation: true,
        warnWhenUnsavedChanges: true,
      }}
    >
      {children}
    </Refine>
  );
}

import { useQuery, useMutation, useQueryClient, keepPreviousData } from '@tanstack/react-query'
import { appointmentApi } from '../api/appointmentApi'
import type {
  Appointment,
  AppointmentFilters,
  AppointmentListResponse,
  BookAppointmentRequest,
  RescheduleAppointmentRequest,
  AppointmentStatus,
} from './types'

export function useGetAppointments(filters: AppointmentFilters) {
  return useQuery({
    queryKey: ['appointments', filters],
    queryFn: () => appointmentApi.getAll(filters),
    placeholderData: keepPreviousData,
  })
}

export function useGetAppointment(id: string) {
  return useQuery({
    queryKey: ['appointments', id],
    queryFn: () => appointmentApi.getById(id),
    enabled: !!id,
  })
}

/**
 * Doctor daily queue — polls every 30 seconds for live updates.
 */
export function useDoctorQueue(doctorId: string, date: string) {
  return useQuery({
    queryKey: ['appointments', 'queue', doctorId, date],
    queryFn: () => appointmentApi.getAll({ doctorId, date, size: 50 }),
    enabled: !!doctorId && !!date,
    refetchInterval: 30_000,
  })
}

export function useBookAppointment() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (data: BookAppointmentRequest) => appointmentApi.create(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['appointments'] })
    },
  })
}

export function useUpdateAppointmentStatus() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ id, status }: { id: string; status: AppointmentStatus }) =>
      appointmentApi.updateStatus(id, status),
    onMutate: async ({ id, status }) => {
      await queryClient.cancelQueries({ queryKey: ['appointments'] })
      const previousAppointment = queryClient.getQueryData<Appointment>(['appointments', id])
      if (previousAppointment) {
        queryClient.setQueryData<Appointment>(['appointments', id], {
          ...previousAppointment,
          status,
        })
      }
      return { previousAppointment }
    },
    onError: (_error, variables, context) => {
      if (context?.previousAppointment) {
        queryClient.setQueryData(['appointments', variables.id], context.previousAppointment)
      }
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ['appointments'] })
    },
  })
}

export function useCancelAppointment() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ id, reason }: { id: string; reason: string }) =>
      appointmentApi.cancel(id, reason),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['appointments'] })
    },
  })
}

export function useRescheduleAppointment() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ id, ...payload }: { id: string } & RescheduleAppointmentRequest) =>
      appointmentApi.reschedule(id, payload),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['appointments'] })
    },
  })
}

export function useJoinWaitlist() {
  return useMutation({
    mutationFn: (id: string) => appointmentApi.joinWaitlist(id),
  })
}

import { apiClient } from '@/shared/api/client'
import { API_ROUTES } from '@/shared/api/apiRoutes'
import type { PaginatedResponse } from '@/shared/types/api'
import type { Patient, CreatePatientRequest, UpdatePatientRequest, PatientFilters } from '../model/types'

export const patientApi = {
  async getAll(filters: PatientFilters): Promise<PaginatedResponse<Patient>> {
    const { data } = await apiClient.get<PaginatedResponse<Patient>>(API_ROUTES.PATIENTS.LIST, {
      params: filters,
    })
    return data
  },

  async getById(id: string): Promise<Patient> {
    const { data } = await apiClient.get<Patient>(API_ROUTES.PATIENTS.DETAIL(id))
    return data
  },

  async create(payload: CreatePatientRequest): Promise<Patient> {
    const { data } = await apiClient.post<Patient>(API_ROUTES.PATIENTS.CREATE, payload)
    return data
  },

  async update(id: string, payload: UpdatePatientRequest): Promise<Patient> {
    const { data } = await apiClient.put<Patient>(API_ROUTES.PATIENTS.DETAIL(id), payload)
    return data
  },

  async getMe(): Promise<Patient> {
    const { data } = await apiClient.get<Patient>(API_ROUTES.PATIENTS.ME)
    return data
  },

  async getMyVisits(): Promise<any> {
    const { data } = await apiClient.get(API_ROUTES.PATIENTS.MY_VISITS)
    return data
  },

  async getMyInvoices(): Promise<any> {
    const { data } = await apiClient.get(API_ROUTES.PATIENTS.MY_INVOICES)
    return data
  },
}

import { apiClient } from '@/shared/api/client'
import { API_ROUTES } from '@/shared/api/apiRoutes'
import type {
  RevenueReport,
  AppointmentsReport,
  VisitsReport,
  DoctorsReport,
  PatientsReport,
  NoShowReport,
  PaginatedAuditLog,
  ReportQueryParams,
  ExportQueryParams,
  AuditLogQueryParams,
} from '../model/reportTypes'

const reportEndpoints: Record<string, string> = {
  appointments: API_ROUTES.ADMIN.REPORTS_APPOINTMENTS,
  revenue: API_ROUTES.ADMIN.REPORTS_REVENUE,
  visits: API_ROUTES.ADMIN.REPORTS_VISITS,
  doctors: API_ROUTES.ADMIN.REPORTS_DOCTORS,
  patients: API_ROUTES.ADMIN.REPORTS_PATIENTS,
  'no-show-rate': API_ROUTES.ADMIN.REPORTS_NO_SHOW,
}

export const reportApi = {
  getAppointmentReport: async (params?: ReportQueryParams) => {
    const { data } = await apiClient.get<AppointmentsReport>(API_ROUTES.ADMIN.REPORTS_APPOINTMENTS, { params })
    return data
  },

  getRevenueReport: async (params?: ReportQueryParams) => {
    const { data } = await apiClient.get<RevenueReport>(API_ROUTES.ADMIN.REPORTS_REVENUE, { params })
    return data
  },

  getVisitsReport: async (params?: ReportQueryParams) => {
    const { data } = await apiClient.get<VisitsReport>(API_ROUTES.ADMIN.REPORTS_VISITS, { params })
    return data
  },

  getDoctorsReport: async (params?: ReportQueryParams) => {
    const { data } = await apiClient.get<DoctorsReport>(API_ROUTES.ADMIN.REPORTS_DOCTORS, { params })
    return data
  },

  getPatientsReport: async (params?: ReportQueryParams) => {
    const { data } = await apiClient.get<PatientsReport>(API_ROUTES.ADMIN.REPORTS_PATIENTS, { params })
    return data
  },

  getNoShowReport: async (params?: ReportQueryParams) => {
    const { data } = await apiClient.get<NoShowReport>(API_ROUTES.ADMIN.REPORTS_NO_SHOW, { params })
    return data
  },

  getAuditLog: async (params?: AuditLogQueryParams) => {
    const { data } = await apiClient.get<PaginatedAuditLog>(API_ROUTES.ADMIN.AUDIT_LOG, { params })
    return data
  },

  exportReport: async (params: ExportQueryParams) => {
    const { data } = await apiClient.get<Blob>(API_ROUTES.ADMIN.REPORTS_EXPORT, {
      params,
      responseType: 'blob',
    })
    return data
  },
}

'use client'

import { useState } from 'react'
import { useBookingStore } from '../model/bookingStore'
import { useGetDoctors } from '@/entities/doctor'
import { useGetAvailableSlots, SlotAvailabilityGrid } from '@/entities/schedule'
import { DoctorCard } from '@/entities/doctor'
import { useAuthStore } from '@/features/auth'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Calendar } from '@/components/ui/calendar'
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { CalendarIcon, ChevronLeft } from 'lucide-react'
import { format } from 'date-fns'
import type { Doctor } from '@/entities/doctor/model/types'
import type { ScheduleSlot } from '@/entities/schedule/model/types'

export function DoctorSlotPicker() {
  const { step, selectedDoctorId, selectedDate, selectedSlot, setStep, selectDoctor, selectDate, selectSlot, reset } = useBookingStore()
  const [specializationFilter, setSpecializationFilter] = useState<string>('')
  const user = useAuthStore((s) => s.user)
  const { data: doctorsData, isLoading: doctorsLoading } = useGetDoctors({ specialization: specializationFilter || undefined, isActive: true })
  const { data: slotData, isLoading: slotsLoading } = useGetAvailableSlots(selectedDoctorId ?? '', selectedDate ?? '')

  const doctors = doctorsData?.content ?? []
  const specializations = [...new Set(doctors.map((d: Doctor) => d.specialization))]

  const handleDoctorSelect = (doctor: Doctor) => {
    selectDoctor(doctor.id)
  }

  const handleDateSelect = (date: Date | undefined) => {
    if (date) {
      selectDate(format(date, 'yyyy-MM-dd'))
    }
  }

  const handleSlotSelect = (slot: ScheduleSlot) => {
    if (slot.isAvailable) {
      selectSlot({ slotStart: slot.startTime, slotEnd: slot.endTime })
    }
  }

  const selectedDoctor = doctors.find((d: Doctor) => d.id === selectedDoctorId)

  const steps = [
    { number: 1, label: 'Select Doctor' },
    { number: 2, label: 'Select Date' },
    { number: 3, label: 'Select Slot' },
    { number: 4, label: 'Confirm' },
  ]

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-center gap-2">
        {steps.map((s, i) => (
          <div key={s.number} className="flex items-center">
            <div className={`flex size-8 items-center justify-center rounded-full text-sm font-medium ${step >= s.number ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'}`}>
              {s.number}
            </div>
            <span className={`ml-2 hidden text-sm sm:inline ${step >= s.number ? 'text-foreground' : 'text-muted-foreground'}`}>
              {s.label}
            </span>
            {i < steps.length - 1 && <div className="mx-3 h-px w-8 bg-border sm:w-12" />}
          </div>
        ))}
      </div>

      {step === 1 && (
        <div className="space-y-4">
          <Select value={specializationFilter} onValueChange={(v) => setSpecializationFilter(v ?? '')}>
            <SelectTrigger className="w-full sm:w-64">
              <SelectValue placeholder="Filter by specialization" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="">All Specializations</SelectItem>
              {specializations.map((s) => (
                <SelectItem key={s} value={s}>{s}</SelectItem>
              ))}
            </SelectContent>
          </Select>
          {doctorsLoading ? (
            <div className="py-8 text-center text-muted-foreground">Loading doctors...</div>
          ) : (
            <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
              {doctors.map((doctor: Doctor) => (
                <DoctorCard key={doctor.id} doctor={doctor} onClick={handleDoctorSelect} />
              ))}
            </div>
          )}
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <Button variant="ghost" size="sm" onClick={() => setStep(1)}>
              <ChevronLeft className="size-4" />
              Back
            </Button>
            <span className="text-sm text-muted-foreground">
              Dr. {selectedDoctor?.firstName} {selectedDoctor?.lastName}
            </span>
          </div>
          <div className="flex justify-center">
            <Popover>
              <PopoverTrigger render={<Button variant="outline" className="w-64 justify-start gap-2" />}>
                <CalendarIcon className="size-4" />
                {selectedDate ? format(new Date(selectedDate), 'PPP') : 'Pick a date'}
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={selectedDate ? new Date(selectedDate) : undefined}
                  onSelect={handleDateSelect}
                  disabled={(date) => date < new Date(new Date().setHours(0, 0, 0, 0))}
                  initialFocus
                />
              </PopoverContent>
            </Popover>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <Button variant="ghost" size="sm" onClick={() => setStep(2)}>
              <ChevronLeft className="size-4" />
              Back
            </Button>
            <span className="text-sm text-muted-foreground">
              Dr. {selectedDoctor?.firstName} {selectedDoctor?.lastName} &middot; {selectedDate}
            </span>
          </div>
          {slotsLoading ? (
            <div className="py-8 text-center text-muted-foreground">Loading slots...</div>
          ) : slotData ? (
            <SlotAvailabilityGrid slotAvailability={slotData} onSelectSlot={handleSlotSelect} />
          ) : (
            <div className="py-8 text-center text-muted-foreground">No slots available.</div>
          )}
        </div>
      )}

      {step === 4 && selectedDoctor && selectedDate && selectedSlot && (
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <Button variant="ghost" size="sm" onClick={() => setStep(3)}>
              <ChevronLeft className="size-4" />
              Back
            </Button>
          </div>
          <Card>
            <CardHeader>
              <CardTitle>Booking Summary</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground">Doctor</span>
                <span>Dr. {selectedDoctor.firstName} {selectedDoctor.lastName}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">Specialization</span>
                <span>{selectedDoctor.specialization}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">Date</span>
                <span>{selectedDate}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">Time</span>
                <span>{selectedSlot.slotStart} – {selectedSlot.slotEnd}</span>
              </div>
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  )
}

import { useMutation, useQueryClient } from "@tanstack/react-query";
import { apiClient } from "@/shared/api/client";
import { API_ROUTES } from "@/shared/api/apiRoutes";
import { useAuthStore } from "@/features/auth/model/authStore";
import type { UpdateUserRequest, AuthUser } from "@/features/auth/model/types";
import { toast } from "sonner";

export function useUpdateProfile() {
  const queryClient = useQueryClient();
  const { setUser } = useAuthStore();

  return useMutation<AuthUser, Error, UpdateUserRequest>({
    mutationFn: async (data: UpdateUserRequest) => {
      const response = await apiClient.put<AuthUser>(API_ROUTES.AUTH.ME, data);
      return response.data;
    },
    onSuccess: (updatedUser) => {
      setUser(updatedUser);
      queryClient.invalidateQueries({ queryKey: ["auth", "me"] });
      toast.success("Profile updated successfully");
    },
    onError: (error: any) => {
      const message = error.response?.data?.message || "Failed to update profile";
      toast.error(message);
    },
  });
}

"use client"

import { useState } from "react"
import { useForm } from "react-hook-form"
import { zodResolver } from "@hookform/resolvers/zod"
import { z } from "zod"
import { toast } from "sonner"
import { apiClient } from "@/shared/api/client"
import { API_ROUTES } from "@/shared/api/apiRoutes"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Loader2Icon, LockIcon } from "lucide-react"

const changePasswordSchema = z.object({
  oldPassword: z.string().min(1, "Current password is required"),
  newPassword: z.string().min(6, "New password must be at least 6 characters"),
  confirmPassword: z.string().min(1, "Please confirm your new password"),
}).refine((data) => data.newPassword === data.confirmPassword, {
  message: "Passwords don't match",
  path: ["confirmPassword"],
})

type ChangePasswordData = z.infer<typeof changePasswordSchema>

interface ChangePasswordFormProps {
  onSuccess?: () => void
}

export function ChangePasswordForm({ onSuccess }: ChangePasswordFormProps) {
  const [isLoading, setIsLoading] = useState(false)

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<ChangePasswordData>({
    resolver: zodResolver(changePasswordSchema),
    defaultValues: {
      oldPassword: "",
      newPassword: "",
      confirmPassword: "",
    },
  })

  const onSubmit = async (data: ChangePasswordData) => {
    setIsLoading(true)
    try {
      await apiClient.post(API_ROUTES.AUTH.CHANGE_PASSWORD, {
        oldPassword: data.oldPassword,
        newPassword: data.newPassword,
      })
      toast.success("Password changed successfully")
      reset()
      onSuccess?.()
    } catch (error: any) {
      const message = error.response?.data?.message || "Failed to change password"
      toast.error(message)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4 py-2">
      <div className="space-y-2">
        <Label htmlFor="oldPassword">Current Password</Label>
        <Input
          id="oldPassword"
          type="password"
          placeholder="••••••••"
          {...register("oldPassword")}
        />
        {errors.oldPassword && (
          <p className="text-xs text-destructive">{errors.oldPassword.message}</p>
        )}
      </div>

      <div className="space-y-2">
        <Label htmlFor="newPassword">New Password</Label>
        <Input
          id="newPassword"
          type="password"
          placeholder="••••••••"
          {...register("newPassword")}
        />
        {errors.newPassword && (
          <p className="text-xs text-destructive">{errors.newPassword.message}</p>
        )}
      </div>

      <div className="space-y-2">
        <Label htmlFor="confirmPassword">Confirm New Password</Label>
        <Input
          id="confirmPassword"
          type="password"
          placeholder="••••••••"
          {...register("confirmPassword")}
        />
        {errors.confirmPassword && (
          <p className="text-xs text-destructive">{errors.confirmPassword.message}</p>
        )}
      </div>

      <div className="flex justify-end gap-3 pt-2">
        <Button type="submit" disabled={isLoading} className="w-full sm:w-auto">
          {isLoading ? (
            <Loader2Icon className="mr-2 size-4 animate-spin" />
          ) : (
            <LockIcon className="mr-2 size-4" />
          )}
          Update Password
        </Button>
      </div>
    </form>
  )
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import {
  getNotifications,
  markNotificationRead,
  markAllNotificationsRead,
  getUnreadCount,
} from './notification.api'
import type {
  Notification,
  PaginatedNotifications,
  NotificationQueryParams,
} from '../model/notification.types'

// ─── Query Keys ──────────────────────────────────────────────

export const notificationKeys = {
  all: ['notifications'] as const,
  list: (params?: NotificationQueryParams) => ['notifications', params] as const,
  unreadCount: ['notifications', 'unread-count'] as const,
}

// ─── Query Hooks ─────────────────────────────────────────────

/**
 * Fetches paginated notifications with 30-second polling.
 */
export function useNotifications(params?: NotificationQueryParams) {
  return useQuery({
    queryKey: notificationKeys.list(params),
    queryFn: () => getNotifications(params),
    refetchInterval: 30_000,
  })
}

/**
 * Fetches the unread notification count with 30-second polling.
 */
export function useUnreadCount() {
  return useQuery({
    queryKey: notificationKeys.unreadCount,
    queryFn: getUnreadCount,
    refetchInterval: 30_000,
  })
}

// ─── Mutation Hooks ──────────────────────────────────────────

/**
 * Marks a single notification as read with optimistic update.
 * - Immediately sets isRead=true in the cache
 * - Decrements unread count optimistically
 * - Rolls back on error
 */
export function useMarkAsRead() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (id: string) => markNotificationRead(id),

    onMutate: async (id: string) => {
      // Cancel outgoing refetches
      await queryClient.cancelQueries({ queryKey: notificationKeys.all })

      // Snapshot previous state
      const previousLists = queryClient.getQueriesData<PaginatedNotifications>({
        queryKey: notificationKeys.all,
      })
      const previousCount = queryClient.getQueryData<{ count: number }>(notificationKeys.unreadCount)

      // Optimistically update all notification list caches
      queryClient.setQueriesData<PaginatedNotifications>(
        { queryKey: notificationKeys.all },
        (old) => {
          if (!old) return old
          return {
            ...old,
            content: old.content.map((n) =>
              n.id === id ? { ...n, isRead: true } : n
            ),
          }
        }
      )

      // Optimistically decrement unread count
      if (previousCount) {
        queryClient.setQueryData(notificationKeys.unreadCount, {
          count: Math.max(0, previousCount.count - 1),
        })
      }

      return { previousLists, previousCount }
    },

    onError: (_error, _id, context) => {
      // Rollback caches
      if (context?.previousLists) {
        for (const [key, data] of context.previousLists) {
          queryClient.setQueryData(key, data)
        }
      }
      if (context?.previousCount) {
        queryClient.setQueryData(notificationKeys.unreadCount, context.previousCount)
      }
    },

    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: notificationKeys.all })
    },
  })
}

/**
 * Marks all notifications as read with optimistic update.
 * - Immediately sets all isRead=true in cache
 * - Resets unread count to 0
 * - Rolls back on error
 */
export function useMarkAllRead() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: markAllNotificationsRead,

    onMutate: async () => {
      await queryClient.cancelQueries({ queryKey: notificationKeys.all })

      const previousLists = queryClient.getQueriesData<PaginatedNotifications>({
        queryKey: notificationKeys.all,
      })
      const previousCount = queryClient.getQueryData<{ count: number }>(notificationKeys.unreadCount)

      // Optimistically mark all as read
      queryClient.setQueriesData<PaginatedNotifications>(
        { queryKey: notificationKeys.all },
        (old) => {
          if (!old) return old
          return {
            ...old,
            content: old.content.map((n) => ({ ...n, isRead: true })),
          }
        }
      )

      // Reset unread count
      queryClient.setQueryData(notificationKeys.unreadCount, { count: 0 })

      return { previousLists, previousCount }
    },

    onError: (_error, _vars, context) => {
      if (context?.previousLists) {
        for (const [key, data] of context.previousLists) {
          queryClient.setQueryData(key, data)
        }
      }
      if (context?.previousCount) {
        queryClient.setQueryData(notificationKeys.unreadCount, context.previousCount)
      }
    },

    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: notificationKeys.all })
    },
  })
}

'use client'

import { useState } from 'react'
import { format } from 'date-fns'
import { toast } from 'sonner'
import { useGetAvailableSlots } from '@/entities/schedule'
import { useBookAppointment } from '@/entities/appointment'
import { useGetDoctor } from '@/entities/doctor'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Calendar } from '@/components/ui/calendar'
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover'
import { Loader2Icon, CalendarIcon } from 'lucide-react'
import { useAuthStore } from '@/features/auth/model/authStore'

interface FollowUpSchedulerProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  visitId: string
  doctorId: string
  patientId: string
  onScheduled?: () => void
}

export function FollowUpScheduler({
  open,
  onOpenChange,
  visitId,
  doctorId,
  patientId,
  onScheduled,
}: FollowUpSchedulerProps) {
  const [selectedDate, setSelectedDate] = useState<Date | undefined>()
  const [selectedSlot, setSelectedSlot] = useState<{ startTime: string; endTime: string } | null>(null)
  const [reason, setReason] = useState('Follow-up appointment')

  const dateStr = selectedDate ? format(selectedDate, 'yyyy-MM-dd') : ''
  const { data: slotData, isLoading: slotsLoading } = useGetAvailableSlots(doctorId, dateStr)
  const bookMutation = useBookAppointment()
  const { data: doctor } = useGetDoctor(doctorId)

  const slots = slotData?.slots?.filter((s) => s.isAvailable) ?? []

  const handleBook = () => {
    if (!selectedSlot || !selectedDate) return

    bookMutation.mutate(
      {
        patientId,
        doctorId,
        slotDate: format(selectedDate, 'yyyy-MM-dd'),
        slotStart: selectedSlot.startTime,
        slotEnd: selectedSlot.endTime,
      },
      {
        onSuccess: () => {
          toast.success('Follow-up appointment booked successfully')
          onScheduled?.()
          onOpenChange(false)
          setSelectedDate(undefined)
          setSelectedSlot(null)
          setReason('Follow-up appointment')
        },
        onError: (error) => {
          const msg = error instanceof Error ? error.message : 'Failed to schedule follow-up'
          toast.error(msg)
        },
      },
    )
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Schedule Follow-up</DialogTitle>
          <DialogDescription>
            Book a follow-up appointment with {doctor ? `Dr. ${doctor.lastName}` : 'the doctor'}
          </DialogDescription>
        </DialogHeader>
        <div className="flex flex-col gap-4">
          <div className="flex flex-col gap-2">
            <Label>Select Date</Label>
            <Popover>
              <PopoverTrigger render={
                <span tabIndex={0}>
                  <Button variant="outline" className="w-full justify-start text-left font-normal">
                    <CalendarIcon className="mr-2 size-4" />
                    {selectedDate ? format(selectedDate, 'PPP') : 'Pick a date'}
                  </Button>
                </span>
              } />
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={selectedDate}
                  onSelect={(date) => {
                    setSelectedDate(date)
                    setSelectedSlot(null)
                  }}
                  disabled={(date) => date < new Date()}
                />
              </PopoverContent>
            </Popover>
          </div>

          {selectedDate && slotsLoading && (
            <div className="flex items-center justify-center py-4">
              <Loader2Icon className="animate-spin size-5" />
            </div>
          )}

          {selectedDate && !slotsLoading && (
            <div className="flex flex-col gap-2">
              <Label>Available Slots</Label>
              {slots.length === 0 ? (
                <p className="text-sm text-muted-foreground py-2">No available slots on this date</p>
              ) : (
                <div className="grid grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                  {slots.map((slot) => (
                    <Button
                      key={slot.startTime}
                      type="button"
                      variant={selectedSlot?.startTime === slot.startTime ? 'default' : 'outline'}
                      size="sm"
                      onClick={() => setSelectedSlot({ startTime: slot.startTime, endTime: slot.endTime })}
                    >
                      {slot.startTime}
                    </Button>
                  ))}
                </div>
              )}
            </div>
          )}

          <div className="flex flex-col gap-2">
            <Label htmlFor="reason">Reason</Label>
            <Input id="reason" value={reason} onChange={(e) => setReason(e.target.value)} />
          </div>
        </div>
        <DialogFooter>
          <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button
            type="button"
            onClick={handleBook}
            disabled={!selectedSlot || !selectedDate || bookMutation.isPending}
          >
            {bookMutation.isPending && <Loader2Icon className="animate-spin" />}
            Book Follow-up
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

'use client'

import { useState } from 'react'
import { useQuery } from '@tanstack/react-query'
import { apiClient } from '@/shared/api/client'
import { API_ROUTES } from '@/shared/api/apiRoutes'
import { useAuthStore } from '@/features/auth/model/authStore'
import { AuthGuard } from '@/features/auth/ui/AuthGuard'
import { formatCurrency } from '@/shared/lib/formatCurrency'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { LoadingSpinner } from '@/shared/ui/loading-spinner/loading-spinner'
import { Button } from '@/components/ui/button'
import {
  CalendarCheckIcon,
  CheckCircleIcon,
  ActivityIcon,
  UserXIcon,
  DollarSignIcon,
  ReceiptIcon,
  TrendingUpIcon,
  TrendingDownIcon,
  MinusIcon,
} from 'lucide-react'
import type { ReactNode } from 'react'

interface MetricCardProps {
  title: string
  value: string | number
  icon: ReactNode
  trend?: { value: number; label: string }
}

function MetricCard({ title, value, icon, trend }: MetricCardProps) {
  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between pb-2">
        <CardTitle className="text-sm font-medium text-muted-foreground">{title}</CardTitle>
        {icon}
      </CardHeader>
      <CardContent>
        <div className="text-2xl font-bold">{value}</div>
        {trend && (
          <div className="flex items-center gap-1 text-xs">
            {trend.value > 0 ? (
              <TrendingUpIcon className="size-3 text-green-600" />
            ) : trend.value < 0 ? (
              <TrendingDownIcon className="size-3 text-red-600" />
            ) : (
              <MinusIcon className="size-3 text-muted-foreground" />
            )}
            <span className={trend.value > 0 ? 'text-green-600' : trend.value < 0 ? 'text-red-600' : 'text-muted-foreground'}>
              {trend.value > 0 ? '+' : ''}{trend.value}% {trend.label}
            </span>
          </div>
        )}
      </CardContent>
    </Card>
  )
}

interface DashboardSummary {
  appointments: {
    total: number
    confirmed: number
    pending: number
    cancelled: number
  }
  revenue: {
    totalBilled: number
    pendingCollected: number
  }
  staff: {
    activeDoctors: number
    totalDoctors: number
  }
}

function useDashboardSummary(from?: string, to?: string) {
  return useQuery({
    queryKey: ['admin', 'dashboard', 'summary', from, to],
    queryFn: async () => {
      const { data } = await apiClient.get<DashboardSummary>(API_ROUTES.ADMIN.DASHBOARD, {
        params: { from, to },
      })
      return data
    },
    staleTime: 5 * 60 * 1000,
  })
}

export default function AdminDashboardPage() {
  const [dateFrom, setDateFrom] = useState<string>(new Date().toISOString().split('T')[0])
  const [dateTo, setDateTo] = useState<string>(new Date().toISOString().split('T')[0])

  const { data: summary, isLoading } = useDashboardSummary(dateFrom || undefined, dateTo || undefined)

  const handleClearRange = () => {
    setDateFrom('')
    setDateTo('')
  }

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  return (
    <AuthGuard requiredRole="Admin">
      <div className="container mx-auto py-6 space-y-6">
        <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
          <h1 className="text-2xl font-bold">Admin Dashboard</h1>
          
          <div className="flex flex-wrap items-center gap-2 bg-muted/50 p-2 rounded-lg border">
            <div className="flex items-center gap-2">
              <span className="text-xs font-medium text-muted-foreground uppercase">From:</span>
              <input
                type="date"
                value={dateFrom}
                onChange={(e) => setDateFrom(e.target.value)}
                className="bg-background border rounded px-2 py-1 text-sm outline-none focus:ring-1 focus:ring-primary"
              />
            </div>
            <div className="flex items-center gap-2">
              <span className="text-xs font-medium text-muted-foreground uppercase">To:</span>
              <input
                type="date"
                value={dateTo}
                onChange={(e) => setDateTo(e.target.value)}
                className="bg-background border rounded px-2 py-1 text-sm outline-none focus:ring-1 focus:ring-primary"
              />
            </div>
            <Button variant="ghost" size="sm" onClick={handleClearRange} className="h-8 text-xs">
              Get All
            </Button>
          </div>
        </div>

        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          <MetricCard
            title="Total Appointments"
            value={summary?.appointments.total ?? 0}
            icon={<CalendarCheckIcon className="size-5 text-blue-500" />}
          />
          <MetricCard
            title="Confirmed Appointments"
            value={summary?.appointments.confirmed ?? 0}
            icon={<CheckCircleIcon className="size-5 text-green-500" />}
          />
          <MetricCard
            title="Active Doctors"
            value={`${summary?.staff.activeDoctors ?? 0} / ${summary?.staff.totalDoctors ?? 0}`}
            icon={<ActivityIcon className="size-5 text-purple-500" />}
          />
          <MetricCard
            title="Total Revenue"
            value={formatCurrency(summary?.revenue.totalBilled ?? 0)}
            icon={<DollarSignIcon className="size-5 text-emerald-500" />}
          />
          <MetricCard
            title="Pending Revenue"
            value={formatCurrency(summary?.revenue.pendingCollected ?? 0)}
            icon={<ReceiptIcon className="size-5 text-yellow-500" />}
          />
          <MetricCard
            title="Cancelled"
            value={summary?.appointments.cancelled ?? 0}
            icon={<UserXIcon className="size-5 text-red-500" />}
          />
        </div>
      </div>
    </AuthGuard>
  )
}

'use client'

import { useState } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { toast } from 'sonner'
import { apiClient } from '@/shared/api/client'
import { API_ROUTES } from '@/shared/api/apiRoutes'
import { AuthGuard } from '@/features/auth/ui/AuthGuard'
import { createUserSchema, createUserBaseSchema, type CreateUserData } from '@/features/auth/model/schemas'
import { DataTable } from '@/shared/ui/data-table/data-table'
import { ConfirmDialog } from '@/shared/ui/confirm-dialog/confirm-dialog'
import { SearchBar } from '@/shared/ui/search-bar/search-bar'
import { LoadingSpinner } from '@/shared/ui/loading-spinner/loading-spinner'
import { EmptyState } from '@/shared/ui/empty-state/empty-state'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog'
import { PlusIcon, PencilIcon, Trash2Icon, Loader2Icon, ShieldCheckIcon, ShieldOffIcon } from 'lucide-react'
import type { ColumnDef } from '@tanstack/react-table'
import type { UserRole } from '@/shared/types/enums'

interface UserItem {
  id: string
  email: string
  firstName: string
  lastName: string
  role: UserRole
  specialization?: string
  isActive?: boolean
}

interface UsersResponse {
  content: UserItem[]
  totalElements: number
  totalPages: number
  page: number
  size: number
}

function useGetUsers(params: { page: number; size: number; search?: string }) {
  return useQuery({
    queryKey: ['admin', 'users', params],
    queryFn: async () => {
      const { data } = await apiClient.get<UsersResponse>(API_ROUTES.USERS.LIST, { params })
      return data
    },
  })
}

function useCreateUser() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (data: { firstName: string; lastName: string; email: string; password: string; role: UserRole; specialization?: string }) =>
      apiClient.post(API_ROUTES.USERS.CREATE, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin', 'users'] })
    },
  })
}

function useUpdateUser() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ id, data }: { id: string; data: { firstName?: string; lastName?: string; email?: string; role?: UserRole; specialization?: string } }) =>
      apiClient.put(API_ROUTES.USERS.DETAIL(id), data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin', 'users'] })
    },
  })
}

function useDeleteUser() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: string) => apiClient.delete(API_ROUTES.USERS.DETAIL(id)),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin', 'users'] })
    },
  })
}

function useToggleDoctorStatus() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ doctorId, isActive }: { doctorId: string; isActive: boolean }) =>
      apiClient.patch(API_ROUTES.ADMIN.DOCTOR_STATUS(doctorId), null, { params: { isActive } }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin', 'users'] })
    },
  })
}

const ROLE_COLORS: Record<UserRole, string> = {
  Admin: 'border-red-500/30 bg-red-500/10 text-red-700 dark:text-red-400',
  Doctor: 'border-blue-500/30 bg-blue-500/10 text-blue-700 dark:text-blue-400',
  Receptionist: 'border-purple-500/30 bg-purple-500/10 text-purple-700 dark:text-purple-400',
  Patient: 'border-green-500/30 bg-green-500/10 text-green-700 dark:text-green-400',
}

function CreateUserForm({
  open,
  onOpenChange,
}: {
  open: boolean
  onOpenChange: (open: boolean) => void
}) {
  const createUserMutation = useCreateUser()

  const {
    register,
    handleSubmit,
    watch,
    reset,
    formState: { errors },
  } = useForm<CreateUserData>({
    resolver: zodResolver(createUserSchema),
    defaultValues: {
      firstName: '',
      lastName: '',
      email: '',
      password: '',
      role: 'Patient',
      specialization: '',
    },
  })

  const selectedRole = watch('role')

  const onSubmit = (data: CreateUserData) => {
    createUserMutation.mutate(data, {
      onSuccess: () => {
        reset()
        onOpenChange(false)
        toast.success('User created successfully')
      },
      onError: () => toast.error('Failed to create user'),
    })
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Create User</DialogTitle>
          <DialogDescription>Add a new user to the system</DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit(onSubmit)} className="flex flex-col gap-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="flex flex-col gap-2">
              <Label htmlFor="create-firstName">First Name</Label>
              <Input id="create-firstName" {...register('firstName')} />
              {errors.firstName && <p className="text-xs text-destructive">{errors.firstName.message}</p>}
            </div>
            <div className="flex flex-col gap-2">
              <Label htmlFor="create-lastName">Last Name</Label>
              <Input id="create-lastName" {...register('lastName')} />
              {errors.lastName && <p className="text-xs text-destructive">{errors.lastName.message}</p>}
            </div>
          </div>
          <div className="flex flex-col gap-2">
            <Label htmlFor="create-email">Email</Label>
            <Input id="create-email" type="email" {...register('email')} />
            {errors.email && <p className="text-xs text-destructive">{errors.email.message}</p>}
          </div>
          <div className="flex flex-col gap-2">
            <Label htmlFor="create-password">Password</Label>
            <Input id="create-password" type="password" {...register('password')} />
            {errors.password && <p className="text-xs text-destructive">{errors.password.message}</p>}
          </div>
          <div className="flex flex-col gap-2">
            <Label htmlFor="create-role">Role</Label>
            <Select value={selectedRole} onValueChange={(v) => register('role').onChange({ target: { value: v, name: 'role' } })}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="Patient">Patient</SelectItem>
                <SelectItem value="Doctor">Doctor</SelectItem>
                <SelectItem value="Receptionist">Receptionist</SelectItem>
                <SelectItem value="Admin">Admin</SelectItem>
              </SelectContent>
            </Select>
            {errors.role && <p className="text-xs text-destructive">{errors.role.message}</p>}
          </div>
          {selectedRole === 'Doctor' && (
            <div className="flex flex-col gap-2">
              <Label htmlFor="create-specialization">Specialization</Label>
              <Input id="create-specialization" placeholder="e.g. Cardiology" {...register('specialization')} />
              {errors.specialization && <p className="text-xs text-destructive">{errors.specialization.message}</p>}
            </div>
          )}
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
              Cancel
            </Button>
            <Button type="submit" disabled={createUserMutation.isPending}>
              {createUserMutation.isPending && <Loader2Icon className="animate-spin mr-2" />}
              Create User
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

function EditUserForm({
  open,
  onOpenChange,
  user,
}: {
  open: boolean
  onOpenChange: (open: boolean) => void
  user: UserItem | null
}) {
  const updateUserMutation = useUpdateUser()

  const {
    register,
    handleSubmit,
    watch,
    reset,
    formState: { errors },
  } = useForm({
    resolver: zodResolver(
      createUserBaseSchema.omit({ password: true }).extend({
        firstName: z.string().min(1, 'First name is required'),
        lastName: z.string().min(1, 'Last name is required'),
        email: z.string().email().min(1, 'Email is required'),
      })
    ),
    defaultValues: {
      firstName: user?.firstName ?? '',
      lastName: user?.lastName ?? '',
      email: user?.email ?? '',
      role: user?.role ?? 'Patient',
      specialization: user?.specialization ?? '',
    },
    values: user
      ? {
          firstName: user.firstName,
          lastName: user.lastName,
          email: user.email,
          role: user.role,
          specialization: user.specialization ?? '',
        }
      : undefined,
  })

  const selectedRole = watch('role')

  const onSubmit = (data: { firstName: string; lastName: string; email: string; role: UserRole; specialization?: string }) => {
    if (!user) return
    updateUserMutation.mutate(
      { id: user.id, data },
      {
        onSuccess: () => {
          onOpenChange(false)
          toast.success('User updated successfully')
        },
        onError: () => toast.error('Failed to update user'),
      },
    )
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Edit User</DialogTitle>
          <DialogDescription>Update user information</DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit(onSubmit)} className="flex flex-col gap-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="flex flex-col gap-2">
              <Label htmlFor="edit-firstName">First Name</Label>
              <Input id="edit-firstName" {...register('firstName')} />
              {errors.firstName && <p className="text-xs text-destructive">{errors.firstName.message}</p>}
            </div>
            <div className="flex flex-col gap-2">
              <Label htmlFor="edit-lastName">Last Name</Label>
              <Input id="edit-lastName" {...register('lastName')} />
              {errors.lastName && <p className="text-xs text-destructive">{errors.lastName.message}</p>}
            </div>
          </div>
          <div className="flex flex-col gap-2">
            <Label htmlFor="edit-email">Email</Label>
            <Input id="edit-email" type="email" {...register('email')} />
            {errors.email && <p className="text-xs text-destructive">{errors.email.message}</p>}
          </div>
          <div className="flex flex-col gap-2">
            <Label htmlFor="edit-role">Role</Label>
            <Select value={selectedRole} onValueChange={(v) => register('role').onChange({ target: { value: v, name: 'role' } })}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="Patient">Patient</SelectItem>
                <SelectItem value="Doctor">Doctor</SelectItem>
                <SelectItem value="Receptionist">Receptionist</SelectItem>
                <SelectItem value="Admin">Admin</SelectItem>
              </SelectContent>
            </Select>
          </div>
          {selectedRole === 'Doctor' && (
            <div className="flex flex-col gap-2">
              <Label htmlFor="edit-specialization">Specialization</Label>
              <Input id="edit-specialization" {...register('specialization')} />
              {errors.specialization && <p className="text-xs text-destructive">{errors.specialization.message}</p>}
            </div>
          )}
          <div className="flex flex-col gap-2">
            <Label htmlFor="edit-password">New Password (leave empty to keep current)</Label>
            <Input id="edit-password" type="password" placeholder="••••••••" {...register('password')} />
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
              Cancel
            </Button>
            <Button type="submit" disabled={updateUserMutation.isPending}>
              {updateUserMutation.isPending && <Loader2Icon className="animate-spin mr-2" />}
              Save Changes
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

export default function UserManagementPage() {
  const [page, setPage] = useState(0)
  const [search, setSearch] = useState('')
  const [createOpen, setCreateOpen] = useState(false)
  const [editOpen, setEditOpen] = useState(false)
  const [deleteOpen, setDeleteOpen] = useState(false)
  const [selectedUser, setSelectedUser] = useState<UserItem | null>(null)
  const [toggleStatusOpen, setToggleStatusOpen] = useState(false)
  const [toggleTarget, setToggleTarget] = useState<UserItem | null>(null)

  const { data, isLoading } = useGetUsers({ page, size: 10, search: search || undefined })
  const deleteUserMutation = useDeleteUser()
  const toggleStatusMutation = useToggleDoctorStatus()

  const handleDelete = () => {
    if (!selectedUser) return
    deleteUserMutation.mutate(selectedUser.id, {
      onSuccess: () => {
        setDeleteOpen(false)
        toast.success(`User ${selectedUser.firstName} ${selectedUser.lastName} deleted`)
      },
      onError: () => toast.error('Failed to delete user'),
    })
  }

  const handleToggleStatus = () => {
    if (!toggleTarget) return
    const newStatus = !toggleTarget.isActive
    toggleStatusMutation.mutate(
      { doctorId: toggleTarget.id, isActive: newStatus },
      {
        onSuccess: () => {
          setToggleStatusOpen(false)
          toast.success(`Doctor ${toggleTarget.firstName} ${toggleTarget.lastName} ${newStatus ? 'activated' : 'deactivated'}`)
        },
        onError: () => toast.error('Failed to toggle doctor status'),
      },
    )
  }

  const columns: ColumnDef<UserItem>[] = [
    {
      accessorKey: 'email',
      header: 'Email',
    },
    {
      id: 'name',
      header: 'Name',
      cell: ({ row }) => `${row.original.firstName} ${row.original.lastName}`,
    },
    {
      accessorKey: 'role',
      header: 'Role',
      cell: ({ row }) => (
        <Badge variant="outline" className={ROLE_COLORS[row.original.role]}>
          {row.original.role}
        </Badge>
      ),
    },
    {
      id: 'status',
      header: 'Status',
      cell: ({ row }) => {
        if (row.original.role !== 'Doctor') return null
        const status = row.original.isActive
        if (status === undefined || status === null) {
          return <Badge variant="outline">Unknown</Badge>
        }
        const isActive = Boolean(row.original.isActive)
        return (
          <Badge 
            variant={isActive ? 'default' : 'secondary'} 
            className={isActive ? 'bg-green-500/10 text-green-700 border-green-500/20' : ''}
          >
            {isActive ? 'Active' : 'Inactive'}
          </Badge>
        )
      },
    },
    {
      id: 'actions',
      header: 'Actions',
      cell: ({ row }) => (
        <div className="flex items-center gap-2">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => {
              setSelectedUser(row.original)
              setEditOpen(true)
            }}
          >
            <PencilIcon className="size-4" />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => {
              setSelectedUser(row.original)
              setDeleteOpen(true)
            }}
          >
            <Trash2Icon className="size-4 text-destructive" />
          </Button>
          {row.original.role === 'Doctor' && (
            <Button
              variant="ghost"
              size="sm"
              onClick={() => {
                setToggleTarget(row.original)
                setToggleStatusOpen(true)
              }}
              title="Toggle active status"
            >
              {Boolean(row.original.isActive) ? (
                <ShieldOffIcon className="size-4 text-orange-500" />
              ) : (
                <ShieldCheckIcon className="size-4 text-green-500" />
              )}
            </Button>
          )}
        </div>
      ),
    },
  ]

  const users = Array.isArray(data) ? data : data?.content ?? []
  const totalPages = Array.isArray(data) ? 1 : data?.totalPages ?? 0

  return (
    <AuthGuard requiredRole="Admin">
      <div className="container mx-auto py-6 space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-bold">User Management</h1>
          <Button onClick={() => setCreateOpen(true)}>
            <PlusIcon className="mr-2 size-4" />
            Create User
          </Button>
        </div>

        <SearchBar onSearch={setSearch} placeholder="Search users..." className="max-w-sm" />

        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <LoadingSpinner size="lg" />
          </div>
        ) : users.length === 0 ? (
          <EmptyState title="No users found" description="Create a user to get started." />
        ) : (
          <DataTable
            columns={columns}
            data={users}
            pagination={{ page, pageSize: 10, totalPages, onPageChange: setPage }}
          />
        )}

        <CreateUserForm open={createOpen} onOpenChange={setCreateOpen} />
        <EditUserForm open={editOpen} onOpenChange={setEditOpen} user={selectedUser} />

        <ConfirmDialog
          open={deleteOpen}
          onOpenChange={setDeleteOpen}
          title="Delete User"
          description={`Are you sure you want to delete ${selectedUser?.firstName} ${selectedUser?.lastName}? This action cannot be undone.`}
          confirmLabel="Delete"
          variant="destructive"
          onConfirm={handleDelete}
          isLoading={deleteUserMutation.isPending}
        />

        <ConfirmDialog
          open={toggleStatusOpen}
          onOpenChange={setToggleStatusOpen}
          title="Toggle Doctor Status"
          description={`Are you sure you want to ${Boolean(toggleTarget?.isActive) ? 'deactivate' : 'activate'} Dr. ${toggleTarget?.firstName} ${toggleTarget?.lastName}?`}
          confirmLabel={Boolean(toggleTarget?.isActive) ? 'Deactivate' : 'Activate'}
          variant={Boolean(toggleTarget?.isActive) ? 'destructive' : 'default'}
          onConfirm={handleToggleStatus}
          isLoading={toggleStatusMutation.isPending}
        />
      </div>
    </AuthGuard>
  )
}

'use client'

import { useParams, useRouter } from 'next/navigation'
import { useState } from 'react'
import { toast } from 'sonner'
import { useGetInvoice, useMarkAsPaid, useWaiveInvoice, InvoiceStatusBadge, LineItemsTable, AmountDisplay } from '@/entities/invoice'
import { useAuthStore } from '@/features/auth/model/authStore'
import { ConfirmDialog } from '@/shared/ui/confirm-dialog/confirm-dialog'
import { LoadingSpinner } from '@/shared/ui/loading-spinner/loading-spinner'
import { EmptyState } from '@/shared/ui/empty-state/empty-state'
import { formatCurrency } from '@/shared/lib/formatCurrency'
import { formatDateTime } from '@/shared/lib/formatDate'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Separator } from '@/components/ui/separator'
import { ArrowLeftIcon, DollarSignIcon, BanIcon } from 'lucide-react'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'

export default function InvoiceDetailPage() {
  const params = useParams<{ id: string }>()
  const router = useRouter()
  const user = useAuthStore((s) => s.user)
  const isAdmin = user?.role === 'Admin'

  const { data: invoice, isLoading, isError } = useGetInvoice(params.id)

  const [payDialogOpen, setPayDialogOpen] = useState(false)
  const [waiveDialogOpen, setWaiveDialogOpen] = useState(false)
  const [waiveReason, setWaiveReason] = useState('')

  const markAsPaidMutation = useMarkAsPaid()
  const waiveMutation = useWaiveInvoice()

  const handleMarkAsPaid = () => {
    if (!invoice) return
    markAsPaidMutation.mutate(invoice.id, {
      onSuccess: () => {
        setPayDialogOpen(false)
        toast.success(`Invoice ${invoice.invoiceNumber} marked as paid`)
      },
      onError: () => toast.error('Failed to mark invoice as paid'),
    })
  }

  const handleWaive = () => {
    if (!invoice || !waiveReason.trim()) return
    waiveMutation.mutate(
      { id: invoice.id, data: { reason: waiveReason.trim() } },
      {
        onSuccess: () => {
          setWaiveDialogOpen(false)
          setWaiveReason('')
          toast.success(`Invoice ${invoice.invoiceNumber} waived`)
        },
        onError: () => toast.error('Failed to waive invoice'),
      },
    )
  }

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  if (isError || !invoice) {
    return <EmptyState title="Invoice not found" description="The requested invoice could not be loaded." />
  }

  return (
    <div className="container mx-auto max-w-4xl py-6 space-y-6">
      <div className="flex items-center gap-4">
        <Button variant="ghost" size="icon" onClick={() => router.back()}>
          <ArrowLeftIcon className="size-4" />
        </Button>
        <div className="flex-1">
          <h1 className="text-2xl font-bold">Invoice {invoice.invoiceNumber}</h1>
          <p className="text-sm text-muted-foreground">Created {formatDateTime(invoice.createdAt)}</p>
        </div>
        <InvoiceStatusBadge status={invoice.status} />
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle>Invoice Details</CardTitle>
            <div className="flex items-center gap-2">
              {invoice.status === 'PENDING' && (
                <Button variant="outline" onClick={() => setPayDialogOpen(true)}>
                  <DollarSignIcon className="mr-2 size-4" />
                  Mark as Paid
                </Button>
              )}
              {isAdmin && invoice.status === 'PENDING' && (
                <Button variant="outline" onClick={() => setWaiveDialogOpen(true)}>
                  <BanIcon className="mr-2 size-4" />
                  Waive
                </Button>
              )}
            </div>
          </div>
        </CardHeader>
        <CardContent className="flex flex-col gap-4">
          <div className="grid grid-cols-2 gap-4 text-sm">
            <div>
              <span className="text-muted-foreground">Patient ID</span>
              <p className="font-medium">{invoice.patientId}</p>
            </div>
            <div>
              <span className="text-muted-foreground">Visit ID</span>
              <p className="font-medium">{invoice.visitId}</p>
            </div>
            {invoice.appointmentId && (
              <div>
                <span className="text-muted-foreground">Appointment ID</span>
                <p className="font-medium">{invoice.appointmentId}</p>
              </div>
            )}
            {invoice.paidAt && (
              <div>
                <span className="text-muted-foreground">Paid At</span>
                <p className="font-medium">{formatDateTime(invoice.paidAt)}</p>
              </div>
            )}
            {invoice.waivedAt && (
              <div>
                <span className="text-muted-foreground">Waived At</span>
                <p className="font-medium">{formatDateTime(invoice.waivedAt)}</p>
              </div>
            )}
            {invoice.waivedReason && (
              <div>
                <span className="text-muted-foreground">Waiver Reason</span>
                <p className="font-medium">{invoice.waivedReason}</p>
              </div>
            )}
          </div>

          <Separator />

          <div>
            <h4 className="mb-3 font-medium">Line Items</h4>
            <LineItemsTable lineItems={invoice.lineItems} />
          </div>

          <Separator />

          <div className="flex justify-end">
            <div className="text-right">
              <span className="text-sm text-muted-foreground">Total Amount</span>
              <p className="text-2xl font-bold">
                <AmountDisplay amount={invoice.totalAmount} />
              </p>
            </div>
          </div>
        </CardContent>
      </Card>

      <ConfirmDialog
        open={payDialogOpen}
        onOpenChange={setPayDialogOpen}
        title="Mark as Paid"
        description={`Mark invoice ${invoice.invoiceNumber} as paid?`}
        confirmLabel="Confirm Payment"
        onConfirm={handleMarkAsPaid}
        isLoading={markAsPaidMutation.isPending}
      />

      <ConfirmDialog
        open={waiveDialogOpen}
        onOpenChange={(open) => {
          setWaiveDialogOpen(open)
          if (!open) setWaiveReason('')
        }}
        title="Waive Invoice"
        description={`Waive invoice ${invoice.invoiceNumber}? This action cannot be undone.`}
        confirmLabel="Waive"
        variant="destructive"
        onConfirm={handleWaive}
        isLoading={waiveMutation.isPending}
      >
        <div className="flex flex-col gap-2 py-2">
          <Label htmlFor="waive-reason-detail">Reason for waiver</Label>
          <Input
            id="waive-reason-detail"
            placeholder="Enter reason for waiving this invoice"
            value={waiveReason}
            onChange={(e) => setWaiveReason(e.target.value)}
          />
        </div>
      </ConfirmDialog>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { toast } from 'sonner'
import { useGetInvoices, useMarkAsPaid, useWaiveInvoice, INVOICE_STATUS_VALUES, InvoiceStatusBadge } from '@/entities/invoice'
import { useAuthStore } from '@/features/auth/model/authStore'
import { DataTable } from '@/shared/ui/data-table/data-table'
import { SearchBar } from '@/shared/ui/search-bar/search-bar'
import { ConfirmDialog } from '@/shared/ui/confirm-dialog/confirm-dialog'
import { LoadingSpinner } from '@/shared/ui/loading-spinner/loading-spinner'
import { EmptyState } from '@/shared/ui/empty-state/empty-state'
import { ROUTE_PATHS } from '@/shared/config/appConfig'
import { formatCurrency } from '@/shared/lib/formatCurrency'
import { formatDate } from '@/shared/lib/formatDate'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { PlusIcon, DollarSignIcon, BanIcon } from 'lucide-react'
import type { ColumnDef } from '@tanstack/react-table'
import type { Invoice } from '@/entities/invoice'
import type { InvoiceStatus } from '@/shared/types/enums'

export default function InvoiceListPage() {
  const router = useRouter()
  const user = useAuthStore((s) => s.user)
  const isAdmin = user?.role === 'Admin'

  const [page, setPage] = useState(0)
  const [statusFilter, setStatusFilter] = useState<InvoiceStatus | undefined>()
  const [search, setSearch] = useState('')

  const [payDialogOpen, setPayDialogOpen] = useState(false)
  const [waiveDialogOpen, setWaiveDialogOpen] = useState(false)
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null)
  const [waiveReason, setWaiveReason] = useState('')

  const { data, isLoading } = useGetInvoices({
    status: statusFilter,
    page,
    size: 10,
  })

  const markAsPaidMutation = useMarkAsPaid()
  const waiveMutation = useWaiveInvoice()

  const handleMarkAsPaid = () => {
    if (!selectedInvoice) return
    markAsPaidMutation.mutate(selectedInvoice.id, {
      onSuccess: () => {
        setPayDialogOpen(false)
        toast.success(`Invoice ${selectedInvoice.invoiceNumber} marked as paid`)
      },
      onError: () => toast.error('Failed to mark invoice as paid'),
    })
  }

  const handleWaive = () => {
    if (!selectedInvoice || !waiveReason.trim()) return
    waiveMutation.mutate(
      { id: selectedInvoice.id, data: { reason: waiveReason.trim() } },
      {
        onSuccess: () => {
          setWaiveDialogOpen(false)
          setWaiveReason('')
          toast.success(`Invoice ${selectedInvoice.invoiceNumber} waived`)
        },
        onError: () => toast.error('Failed to waive invoice'),
      },
    )
  }

  const columns: ColumnDef<Invoice>[] = [
    {
      accessorKey: 'invoiceNumber',
      header: 'Invoice #',
    },
    {
      accessorKey: 'patientName',
      header: 'Patient',
      cell: ({ row }) => row.original.patientName ?? row.original.patientId,
    },
    {
      accessorKey: 'createdAt',
      header: 'Date',
      cell: ({ row }) => formatDate(row.original.createdAt),
    },
    {
      accessorKey: 'totalAmount',
      header: 'Amount',
      cell: ({ row }) => formatCurrency(row.original.totalAmount),
    },
    {
      accessorKey: 'status',
      header: 'Status',
      cell: ({ row }) => <InvoiceStatusBadge status={row.original.status} />,
    },
    {
      id: 'actions',
      header: 'Actions',
      cell: ({ row }) => {
        const invoice = row.original
        return (
          <div className="flex items-center gap-2">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => router.push(`${ROUTE_PATHS.ADMIN_BILLING}/${invoice.id}`)}
            >
              View
            </Button>
            {invoice.status === 'PENDING' && (
              <Button
                variant="outline"
                size="sm"
                onClick={() => {
                  setSelectedInvoice(invoice)
                  setPayDialogOpen(true)
                }}
              >
                <DollarSignIcon className="mr-1 size-3" />
                Pay
              </Button>
            )}
            {isAdmin && invoice.status === 'PENDING' && (
              <Button
                variant="outline"
                size="sm"
                onClick={() => {
                  setSelectedInvoice(invoice)
                  setWaiveDialogOpen(true)
                }}
              >
                <BanIcon className="mr-1 size-3" />
                Waive
              </Button>
            )}
          </div>
        )
      },
    },
  ]

  const invoices = data?.content ?? []
  const totalPages = data?.totalPages ?? 0

  return (
    <div className="container mx-auto py-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">Invoices</h1>
        <Button onClick={() => router.push(`${ROUTE_PATHS.ADMIN_BILLING}/create`)}>
          <PlusIcon className="mr-2 size-4" />
          Create Invoice
        </Button>
      </div>

      <div className="flex items-center gap-4">
        <SearchBar onSearch={setSearch} placeholder="Search invoices..." />
        <Select value={statusFilter ?? 'all'} onValueChange={(v) => setStatusFilter(v === 'all' ? undefined : (v as InvoiceStatus))}>
          <SelectTrigger className="w-[180px]">
            <SelectValue placeholder="Filter status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Statuses</SelectItem>
            {INVOICE_STATUS_VALUES.map((s) => (
              <SelectItem key={s} value={s}>{s}</SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <LoadingSpinner size="lg" />
        </div>
      ) : invoices.length === 0 ? (
        <EmptyState title="No invoices found" description="Create an invoice to get started." />
      ) : (
        <DataTable
          columns={columns}
          data={invoices}
          pagination={{ page, pageSize: 10, totalPages, onPageChange: setPage }}
        />
      )}

      <ConfirmDialog
        open={payDialogOpen}
        onOpenChange={setPayDialogOpen}
        title="Mark as Paid"
        description={`Mark invoice ${selectedInvoice?.invoiceNumber ?? ''} as paid?`}
        confirmLabel="Confirm Payment"
        onConfirm={handleMarkAsPaid}
        isLoading={markAsPaidMutation.isPending}
      />

      <ConfirmDialog
        open={waiveDialogOpen}
        onOpenChange={(open) => {
          setWaiveDialogOpen(open)
          if (!open) setWaiveReason('')
        }}
        title="Waive Invoice"
        description={`Waive invoice ${selectedInvoice?.invoiceNumber ?? ''}? This action cannot be undone.`}
        confirmLabel="Waive"
        variant="destructive"
        onConfirm={handleWaive}
        isLoading={waiveMutation.isPending}
      >
        <div className="flex flex-col gap-2 py-2">
          <Label htmlFor="waive-reason">Reason for waiver</Label>
          <Input
            id="waive-reason"
            placeholder="Enter reason for waiving this invoice"
            value={waiveReason}
            onChange={(e) => setWaiveReason(e.target.value)}
          />
        </div>
      </ConfirmDialog>
    </div>
  )
}

'use client'

import { useParams } from 'next/navigation'
import { useGetVisit, VisitDetail, VisitStatusBadge, PrescriptionCard, PdfDownloadButton } from '@/entities/visit'
import { LoadingSpinner } from '@/shared/ui/loading-spinner/loading-spinner'
import { EmptyState } from '@/shared/ui/empty-state/empty-state'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Separator } from '@/components/ui/separator'
import { LockIcon } from 'lucide-react'
import { formatDateTime } from '@/shared/lib/formatDate'

export default function VisitDetailPage() {
  const params = useParams<{ id: string }>()
  const visitId = params.id

  const { data: visit, isLoading, isError } = useGetVisit(visitId)

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  if (isError || !visit) {
    return (
      <EmptyState title="Visit not found" description="The requested visit record could not be loaded." />
    )
  }

  return (
    <div className="container mx-auto max-w-4xl py-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">Visit Record</h1>
        <div className="flex items-center gap-3">
          <VisitStatusBadge isSigned={visit.isSigned} />
          <PdfDownloadButton visitId={visit.id} />
        </div>
      </div>

      {visit.isSigned && (
        <Card className="border-green-200 bg-green-50/50">
          <CardContent className="flex items-center gap-2 py-3">
            <LockIcon className="size-4 text-green-600" />
            <span className="text-sm text-green-700">
              This visit has been signed and locked on {formatDateTime(visit.signedAt)}
            </span>
          </CardContent>
        </Card>
      )}

      <VisitDetail visit={visit} />

      {visit.prescriptions.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Prescriptions</CardTitle>
          </CardHeader>
          <CardContent className="flex flex-col gap-2">
            {visit.prescriptions.map((rx) => (
              <PrescriptionCard key={rx.id} prescription={rx} />
            ))}
          </CardContent>
        </Card>
      )}

      <div className="text-xs text-muted-foreground">
        Visit ID: {visit.id} · Created: {formatDateTime(visit.createdAt)} · Updated: {formatDateTime(visit.updatedAt)}
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { useParams } from 'next/navigation'
import { toast } from 'sonner'
import { useCreateVisit, useSignVisit, useIssuePrescription, useScheduleFollowUp } from '@/entities/visit'
import { useGetAppointment } from '@/entities/appointment'
import { VisitForm, PrescriptionForm, SignVisitDialog, FollowUpScheduler } from '@/features/visit-form'
import { useVisitFormStore } from '@/features/visit-form/model/visitFormStore'
import { LoadingSpinner } from '@/shared/ui/loading-spinner/loading-spinner'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Separator } from '@/components/ui/separator'
import { PillIcon, FileCheckIcon, CalendarPlusIcon, SaveIcon, Trash2Icon } from 'lucide-react'
import type { CreateVisitFormData, PrescriptionFormData } from '@/features/visit-form'

export default function VisitPage() {
  const params = useParams()
  const appointmentId = (params.appointmentId ?? params.id) as string

  const { data: appointment, isLoading: appointmentLoading } = useGetAppointment(appointmentId)
  const createVisitMutation = useCreateVisit()
  const signVisitMutation = useSignVisit()
  const issuePrescriptionMutation = useIssuePrescription()
  const scheduleFollowUpMutation = useScheduleFollowUp()

  const [prescriptionOpen, setPrescriptionOpen] = useState(false)
  const [signDialogOpen, setSignDialogOpen] = useState(false)
  const [followUpOpen, setFollowUpOpen] = useState(false)
  const [createdVisitId, setCreatedVisitId] = useState<string | null>(null)

  const prescriptions = useVisitFormStore((s) => s.prescriptions)
  const removePrescription = useVisitFormStore((s) => s.removePrescription)

  const handleSaveVisit = (data: CreateVisitFormData) => {
    createVisitMutation.mutate(data, {
      onSuccess: (visit) => {
        setCreatedVisitId(visit.id)
        toast.success('Visit record created successfully')
      },
      onError: (error) => {
        const message = error instanceof Error ? error.message : 'Failed to create visit'
        toast.error(message)
      },
    })
  }

  const handleIssuePrescription = (data: PrescriptionFormData) => {
    if (!createdVisitId) return
    issuePrescriptionMutation.mutate(
      { visitId: createdVisitId, data },
      {
        onSuccess: () => toast.success('Prescription added successfully'),
        onError: (error) => {
          const msg = error instanceof Error ? error.message : 'Failed to add prescription'
          toast.error(msg)
        },
      }
    )
  }

  const handleSignVisit = (additionalItems: { description: string; quantity: number; unitPrice: number }[]) => {
    if (!createdVisitId) return
    signVisitMutation.mutate(
      { id: createdVisitId, data: { additionalItems } },
      {
        onSuccess: () => {
          useVisitFormStore.getState().reset()
          toast.success('Visit signed and locked successfully')
        },
        onError: (error) => {
          const msg = error instanceof Error ? error.message : 'Failed to sign visit'
          toast.error(msg)
        },
      },
    )
  }

  const handleScheduleFollowUp = () => {}

  if (appointmentLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  const isVisitCreated = !!createdVisitId

  return (
    <div className="container mx-auto max-w-4xl py-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Visit Workspace</h1>
          {appointment && (
            <p className="text-sm text-muted-foreground">
              Appointment: {appointment.slotDate} · {appointment.slotStart} - {appointment.slotEnd}
            </p>
          )}
        </div>
        {isVisitCreated && (
          <Badge variant="outline" className="border-green-500/30 bg-green-500/10 text-green-700">
            Visit Saved
          </Badge>
        )}
      </div>

      <VisitForm appointmentId={appointmentId} onSubmit={handleSaveVisit} isSubmitting={createVisitMutation.isPending} />

      <div className="flex gap-3">
        <Button
          type="submit"
          form="visit-form"
          disabled={createVisitMutation.isPending || isVisitCreated}
        >
          <SaveIcon className="mr-2 size-4" />
          Save Visit
        </Button>
        <Button
          type="button"
          variant="outline"
          onClick={() => setPrescriptionOpen(true)}
          disabled={!isVisitCreated || signVisitMutation.isSuccess}
        >
          <PillIcon className="mr-2 size-4" />
          Issue Prescription
        </Button>
        <Button
          type="button"
          variant="outline"
          onClick={() => setSignDialogOpen(true)}
          disabled={!isVisitCreated || signVisitMutation.isSuccess}
        >
          <FileCheckIcon className="mr-2 size-4" />
          Sign Visit
        </Button>
        <Button
          type="button"
          variant="outline"
          onClick={() => setFollowUpOpen(true)}
          disabled={!isVisitCreated}
        >
          <CalendarPlusIcon className="mr-2 size-4" />
          Schedule Follow-up
        </Button>
      </div>

      {prescriptions.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Prescriptions</CardTitle>
          </CardHeader>
          <CardContent className="flex flex-col gap-2">
            {prescriptions.map((rx, i) => (
              <div key={i} className="flex items-center justify-between rounded-lg border p-3">
                <div>
                  <p className="font-medium">{rx.medicationName}</p>
                  <p className="text-sm text-muted-foreground">
                    {rx.dosage} · {rx.frequency} · {rx.durationDays} days
                  </p>
                  {rx.notes && <p className="text-xs text-muted-foreground">{rx.notes}</p>}
                </div>
                {!isVisitCreated || !signVisitMutation.isSuccess ? (
                  <Button type="button" variant="ghost" size="icon" onClick={() => removePrescription(i)}>
                    <Trash2Icon className="size-4 text-destructive" />
                  </Button>
                ) : null}
              </div>
            ))}
          </CardContent>
        </Card>
      )}

      <PrescriptionForm
        open={prescriptionOpen}
        onOpenChange={setPrescriptionOpen}
        onSubmit={handleIssuePrescription}
        isSubmitting={issuePrescriptionMutation.isPending}
      />

      <SignVisitDialog
        open={signDialogOpen}
        onOpenChange={setSignDialogOpen}
        onConfirm={handleSignVisit}
        isSubmitting={signVisitMutation.isPending}
      />

      <FollowUpScheduler
        open={followUpOpen}
        onOpenChange={setFollowUpOpen}
        visitId={createdVisitId ?? ''}
        doctorId={appointment?.doctorId ?? ''}
        patientId={appointment?.patientId ?? ''}
      />
    </div>
  )
}

"use client";

import * as React from "react";
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  useReactTable,
  type SortingState,
  type ColumnFiltersState,
} from "@tanstack/react-table";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

interface DataTableProps<TData, TValue> {
  columns: ColumnDef<TData, TValue>[];
  data: TData[];
  pagination: {
    page: number;
    pageSize: number;
    totalPages: number;
    onPageChange: (page: number) => void;
  };
  isLoading?: boolean;
  onSortingChange?: (sorting: SortingState) => void;
  onColumnFiltersChange?: (filters: ColumnFiltersState) => void;
  searchPlaceholder?: string;
  searchKey?: string;
}

export function DataTable<TData, TValue>({
  columns,
  data,
  pagination,
  isLoading,
  onSortingChange,
  onColumnFiltersChange,
  searchPlaceholder,
  searchKey,
}: DataTableProps<TData, TValue>) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>(
    []
  );

  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
    onSortingChange: (updater) => {
      const newSorting =
        typeof updater === "function" ? updater(sorting) : updater;
      setSorting(newSorting);
      onSortingChange?.(newSorting);
    },
    onColumnFiltersChange: (updater) => {
      const newFilters =
        typeof updater === "function" ? updater(columnFilters) : updater;
      setColumnFilters(newFilters);
      onColumnFiltersChange?.(newFilters);
    },
    state: {
      sorting,
      columnFilters,
    },
  });

  return (
    <div className="space-y-4">
      {searchKey && (
        <div className="flex items-center">
          <Input
            placeholder={searchPlaceholder || "Search..."}
            value={
              (table.getColumn(searchKey)?.getFilterValue() as string) ?? ""
            }
            onChange={(event) =>
              table.getColumn(searchKey)?.setFilterValue(event.target.value)
            }
            className="max-w-sm"
          />
        </div>
      )}
      <div className="rounded-md border">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <TableHead key={header.id}>
                    {header.isPlaceholder
                      ? null
                      : flexRender(
                          header.column.columnDef.header,
                          header.getContext()
                        )}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {isLoading ? (
              <TableRow>
                <TableCell
                  colSpan={columns.length}
                  className="h-24 text-center"
                >
                  Loading...
                </TableCell>
              </TableRow>
            ) : table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  data-state={row.getIsSelected() && "selected"}
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id}>
                      {flexRender(
                        cell.column.columnDef.cell,
                        cell.getContext()
                      )}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell
                  colSpan={columns.length}
                  className="h-24 text-center"
                >
                  No results.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>
      <div className="flex items-center justify-between px-2">
        <p className="text-sm text-muted-foreground">
          Page {pagination.page + 1} of {pagination.totalPages}
        </p>
        <div className="flex items-center space-x-2">
          <Button
            variant="outline"
            size="sm"
            onClick={() => pagination.onPageChange(pagination.page - 1)}
            disabled={pagination.page <= 0}
          >
            Previous
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={() => pagination.onPageChange(pagination.page + 1)}
            disabled={pagination.page >= pagination.totalPages - 1}
          >
            Next
          </Button>
        </div>
      </div>
    </div>
  );
}

"use client";

import * as React from "react";
import { format } from "date-fns";
import { CalendarIcon } from "lucide-react";
import { DateRange } from "react-day-picker";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";

interface DateRangePickerProps {
  dateRange: DateRange | undefined;
  onDateRangeChange: (range: DateRange | undefined) => void;
  className?: string;
  fromPlaceholder?: string;
  toPlaceholder?: string;
}

export function DateRangePicker({
  dateRange,
  onDateRangeChange,
  className,
  fromPlaceholder = "From",
  toPlaceholder = "To",
}: DateRangePickerProps) {
  return (
    <div className={cn("grid gap-2", className)}>
      <Popover>
        <PopoverTrigger render={<Button variant="outline" id="date" />}>
          <CalendarIcon className="mr-2 size-4" />
          {dateRange?.from ? (
            dateRange.to ? (
              <>
                {format(dateRange.from, "LLL d, y")} -{" "}
                {format(dateRange.to, "LLL d, y")}
              </>
            ) : (
              format(dateRange.from, "LLL d, y")
            )
          ) : (
            <span>{fromPlaceholder}</span>
          )}
        </PopoverTrigger>
        <PopoverContent className="w-auto p-0" align="start">
          <Calendar
            mode="range"
            defaultMonth={dateRange?.from}
            selected={dateRange}
            onSelect={onDateRangeChange}
            numberOfMonths={2}
          />
        </PopoverContent>
      </Popover>
    </div>
  );
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import type { ColumnDef } from '@tanstack/react-table'
import { useGetVisits, VisitStatusBadge } from '@/entities/visit'
import type { Visit, VisitFilters } from '@/entities/visit'
import { DataTable } from '@/shared/ui/data-table/data-table'
import { LoadingSpinner } from '@/shared/ui/loading-spinner/loading-spinner'
import { EmptyState } from '@/shared/ui/empty-state/empty-state'
import { formatDate } from '@/shared/lib/formatDate'
import { FileTextIcon, PillIcon } from 'lucide-react'

interface VisitHistoryTableProps {
  patientId?: string
  doctorId?: string
}

export function VisitHistoryTable({ patientId, doctorId }: VisitHistoryTableProps) {
  const router = useRouter()
  const [page, setPage] = useState(0)

  const filters: VisitFilters = {
    patientId,
    doctorId,
    page,
    size: 10,
  }

  const { data, isLoading } = useGetVisits(filters)
  const visits = data?.content ?? []

  const columns: ColumnDef<Visit>[] = [
    {
      accessorKey: 'chiefComplaint',
      header: 'Chief Complaint',
      cell: ({ row }) => (
        <div className="flex items-center gap-2">
          <FileTextIcon className="size-4 text-muted-foreground" />
          <span className="max-w-xs truncate">{row.original.chiefComplaint}</span>
        </div>
      ),
    },
    {
      accessorKey: 'assessment',
      header: 'Assessment',
      cell: ({ row }) => (
        <span className="max-w-xs truncate text-muted-foreground">
          {row.original.assessment}
        </span>
      ),
    },
    {
      accessorKey: 'icd10Codes',
      header: 'ICD-10',
      cell: ({ row }) =>
        row.original.icd10Codes.length > 0
          ? row.original.icd10Codes.join(', ')
          : '—',
    },
    {
      accessorKey: 'prescriptions',
      header: 'Rx',
      cell: ({ row }) =>
        row.original.prescriptions.length > 0 ? (
          <span className="flex items-center gap-1">
            <PillIcon className="size-3" />
            {row.original.prescriptions.length}
          </span>
        ) : (
          '—'
        ),
    },
    {
      accessorKey: 'isSigned',
      header: 'Status',
      cell: ({ row }) => <VisitStatusBadge isSigned={row.original.isSigned} />,
    },
    {
      accessorKey: 'createdAt',
      header: 'Date',
      cell: ({ row }) => formatDate(row.original.createdAt),
    },
  ]

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  if (visits.length === 0) {
    return (
      <EmptyState
        icon={FileTextIcon}
        title="No visit records"
        description="No visit records found for the selected filters."
      />
    )
  }

  return (
    <DataTable
      columns={columns}
      data={visits}
      pagination={{
        page: data?.number ?? 0,
        pageSize: 10,
        totalPages: data?.totalPages ?? 1,
        onPageChange: setPage,
      }}
    />
  )
}
